namespace Dataphyre\Panel;

/**
 * Emits mobile-first corrective CSS for dense Panel interfaces.
 *
 * This asset is layered after core panel styles to keep generated navigation,
 * tables, forms, modals, command palettes, action groups, and relation managers
 * usable on narrow or coarse-pointer devices. It is static CSS; renderer state is
 * communicated through classes, data attributes, and custom properties.
 */
trait PanelRendererAssetsMobileCss {
	/**
	 * Returns the responsive mobile interaction stylesheet.
